/* ── XP / LEVEL MATH ───────────────────────────────────────────────────────
   totalXPForLevel(L) = 0.36·L³
   Verified: L10 = 360 XP (1 h), L100 = 360,000 XP (1000 h)
   1 XP = 10 s of practice; sessions < 10 s are discarded. */
const LEVEL_A = 0.36;
const totalXPForLevel = L => Math.round(LEVEL_A * Math.max(0,L) ** 3);
const levelFromTotalXP = xp => Math.max(1, Math.floor((Math.max(0,xp) / LEVEL_A) ** (1/3)));
const xpForNextLevel   = L => totalXPForLevel(L+1) - totalXPForLevel(L);

const STAT_COLORS = { str:"#a87878", vit:"#a88868", wil:"#a09870", hrt:"#7a9a7a", voi:"#7888a8", wis:"#8880a4", ali:"#a898b8" };


/* Invert STAT_MAP → which session types contribute to each stat */
const _TYPE_LABELS = {sitting:"Sit",standing:"Stand",walking:"Walk"};
const STAT_SOURCES = {};
Object.entries(STAT_MAP).forEach(([type,stats])=>{
  const lbl = _TYPE_LABELS[type]||(type.charAt(0).toUpperCase()+type.slice(1));
  Object.keys(stats).forEach(k=>{
    if(!STAT_SOURCES[k]) STAT_SOURCES[k]=[];
    STAT_SOURCES[k].push(lbl);
  });
});
// Journal contributes to HRT, VOI, WIS
["hrt","voi","wis"].forEach(k=>{ if(!STAT_SOURCES[k]) STAT_SOURCES[k]=[]; STAT_SOURCES[k].push("Journal"); });

/* ── STAT MIGRATION ─────────────────────────────────────────────────────────
   Handles two schema changes at once:
   a) Rename: per→wis (Clarity), wis→ali (Alignment)
   b) Stat values: raw 0-100 → XP storage (multiply by totalXPForLevel)
   Detected via _statsFmt:"xp" flag. */
function migrateCh(ch){
  if(!ch) return null;
  if(ch._statsFmt==="xp") return ch; // already current
  const old = ch.stats||{};
  const stats = {};
  // Rename and convert to XP in one pass
  Object.entries(old).forEach(([k,v])=>{
    const newK = k==="per"?"wis" : k==="wis"?"ali" : k;
    // If value looks like a raw level (0-100), convert to XP; else keep (already XP)
    stats[newK] = v<=100 ? totalXPForLevel(Math.round(v)) : v;
  });
  if(!stats.wis) stats.wis=0;
  if(!stats.ali) stats.ali=0;
  const totalXP = ch.totalXP ?? (totalXPForLevel(ch.level||1)+(ch.xp||0));
  return {...ch, stats, totalXP, _statsFmt:"xp"};
}

function rewards(typeId, sessionXP, activeActivities=[]){
  const baseStats = STAT_MAP[typeId]||STAT_MAP.sitting;
  const baseCount = Math.max(Object.keys(baseStats).length, 3);
  const denom = baseCount + activeActivities.length;
  const sg={};
  Object.entries(baseStats).forEach(([k,v])=>{
    sg[k]=(sg[k]||0)+Math.max(1,Math.round(sessionXP*v*baseCount/denom));
  });
  activeActivities.forEach(act=>{
    sg[act.stat]=(sg[act.stat]||0)+Math.max(1,Math.round(sessionXP*baseCount/denom));
  });
  return { sg };
}
function playBell(){
  try{
    const ctx=new(window.AudioContext||window.webkitAudioContext)();
    [[528,.4],[1056,.2],[1584,.1]].forEach(([f,v])=>{
      const o=ctx.createOscillator(),g=ctx.createGain();
      o.connect(g);g.connect(ctx.destination);
      o.frequency.setValueAtTime(f,ctx.currentTime);
      o.frequency.exponentialRampToValueAtTime(f*.94,ctx.currentTime+2.5);
      g.gain.setValueAtTime(v,ctx.currentTime);
      g.gain.exponentialRampToValueAtTime(.001,ctx.currentTime+3.5);
      o.start(ctx.currentTime);o.stop(ctx.currentTime+3.5);
    });
  }catch(e){}
}

