function lerpHex(a,b,t){
  const p=h=>{const n=parseInt(h.slice(1),16);return[(n>>16)&255,(n>>8)&255,n&255];};
  const [ar,ag,ab]=p(a),[br,bg,bb]=p(b);
  return '#'+[ar+(br-ar)*t,ag+(bg-ag)*t,ab+(bb-ab)*t].map(v=>Math.round(v).toString(16).padStart(2,'0')).join('');
}
function MorningScene({ sceneIdx=0, paraPage=0, progOverride=null }){
  const prog    = progOverride!=null ? progOverride : Math.min(sceneIdx + paraPage*0.5, 3.5);
  const skyProg = (prog / 3.5) * (MSKY.length - 1);
  const i0  = Math.min(Math.floor(skyProg), MSKY.length-1);
  const i1  = Math.min(i0+1, MSKY.length-1);
  const lt  = skyProg - Math.floor(skyProg);
  const sky = Object.fromEntries(["t","u","l","h"].map(k=>[k,lerpHex(MSKY[i0][k],MSKY[i1][k],lt)]));
  const sunA= MSKY[i0].sa + (MSKY[i1].sa - MSKY[i0].sa)*lt;
  const mtnT = Math.min(prog / 2.5, 1);
  const mtnFill = MTN_NIGHT.map((n,i) => lerpHex(n, MTN_DAY[i], mtnT));
  const PAN_DUR = [22, 15, 10, 7, 4.5];
  const PAN_DEL = [-4, -7, -2, -9, -1];
  return (
    <svg width="100%" height="100%" viewBox="0 0 390 700" preserveAspectRatio="xMidYMid slice" style={{position:"absolute",inset:0,display:"block"}}>
      <defs>
        <linearGradient id="msky" x1="0" y1="0" x2="0" y2="1">
          <stop offset="0%"   stopColor={sky.t}/>
          <stop offset="28%"  stopColor={sky.u}/>
          <stop offset="58%"  stopColor={sky.l}/>
          <stop offset="78%"  stopColor={sky.h}/>
          <stop offset="100%" stopColor={sky.h}/>
        </linearGradient>
        <radialGradient id="mglw" cx="50%" cy="60%" r="55%">
          <stop offset="0%"   stopColor="#f06020" stopOpacity={sunA*0.85}/>
          <stop offset="40%"  stopColor="#b02818" stopOpacity={sunA*0.5}/>
          <stop offset="100%" stopColor="#b02818" stopOpacity="0"/>
        </radialGradient>
        <radialGradient id="msun" cx="50%" cy="62%" r="20%">
          <stop offset="0%"   stopColor="#ffe8a0" stopOpacity={Math.min(sunA*1.4,1)}/>
          <stop offset="60%"  stopColor="#ffc060" stopOpacity={sunA*0.6}/>
          <stop offset="100%" stopColor="#ffc060" stopOpacity="0"/>
        </radialGradient>
      </defs>
      <rect width="390" height="700" fill="url(#msky)"/>
      <rect width="390" height="700" fill="url(#mglw)"/>
      <rect width="390" height="700" fill="url(#msun)"/>
      {[[42,80],[130,55],[210,40],[300,70],[350,45],[80,110],[260,95],[175,120],[320,100],[155,65],[290,130]].map(([x,y],i)=>(
        <circle key={i} cx={x} cy={y} r="0.9" fill="white" opacity={Math.max(0,(1-sunA*2)*0.8)}/>
      ))}
      {MTN_PATHS.map((d,i)=>(
        <g key={i}>
          <animateTransform attributeName="transform" type="translate"
            from="0,0" to="-800,0"
            dur={PAN_DUR[i]+"s"} begin={PAN_DEL[i]+"s"} repeatCount="indefinite"/>
          <path d={d} fill={mtnFill[i]} opacity={MTN_OPA[i]}/>
        </g>
      ))}
    </svg>
  );
}

