function Radar({ stats, size=210, circular=false, showLabels=true, totalXP=0 }){
  const cx=size/2, cy=size/2, r=size*.32, n=STATS.length;
  const ang=STATS.map((_,i)=>Math.PI*2*i/n-Math.PI/2);
  const pt=(ai,ratio)=>[cx+Math.cos(ang[ai])*r*ratio, cy+Math.sin(ang[ai])*r*ratio];
  const ring=ratio=>STATS.map((_,i)=>pt(i,ratio).join(",")).join(" ");
  /* Visibility zoom: vizFactor 10→1 over character levels 1→100 (linear).
     Multiplies each stat's radar position so low stats show up early.
     L1 stat = small dot (~10% radius), L2 = 20%, L5 = 50%.
     At charLevel 100, vizFactor=1 so stats show their true ratio. */
  /* Power-curve visibility: exponent 0.5→1 over levels 1→100.
     Never caps before stat=100. At L1: stat1=10%(dot), stat2=14%(visible).
     At L100: stat80=80% exactly. */
  const charLevel = levelFromTotalXP(totalXP);
  const vizPow = 1 + 2*(100-charLevel)/99; // 3 at L1, 1 at L100
  const scale = 0.6 + 0.4*(charLevel-1)/99; // 0.6 at L1, 1.0 at L100
  const statRatio = k => {
    const lvl = levelFromTotalXP(stats[k]||0);
    const raw = Math.pow(clamp(lvl/100, 0.001, 1), 1/vizPow) * scale;
    return Math.min(1, lvl <= 1 ? raw * 0.3 : raw); // stat L1 = tiny dot; L2+ on normal curve
  };
  const shape=STATS.map(({k},i)=>pt(i,statRatio(k)).join(",")).join(" ");
  const pts=STATS.map(({k},i)=>pt(i,statRatio(k)));
  const uid=`rfill${size}`; // unique gradient id per size to avoid conflicts
  return (
    <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`} overflow="visible" style={{overflow:"visible"}}>
      <defs>
        <radialGradient id={uid} cx="50%" cy="50%" r="50%">
          <stop offset="0%" stopColor="rgba(163,192,137,0.32)"/>
          <stop offset="100%" stopColor="rgba(201,168,76,0.06)"/>
        </radialGradient>
      </defs>
      {ang.map((a,i)=><line key={i} x1={cx} y1={cy} x2={cx+Math.cos(a)*r} y2={cy+Math.sin(a)*r} stroke={C.bord} strokeWidth="0.6"/>)}
      {circular
        ? [.25,.5,.75,1].map((rt,i)=><circle key={i} cx={cx} cy={cy} r={r*rt} fill="none" stroke={i===3?C.goldDim:"rgba(125,154,106,0.12)"} strokeWidth={i===3?0.8:0.5}/>)
        : [.25,.5,.75,1].map((rt,i)=><polygon key={i} points={ring(rt)} fill="none" stroke={i===3?C.goldDim:"rgba(125,154,106,0.12)"} strokeWidth={i===3?0.8:0.5}/>)
      }
      <polygon points={shape} fill={`url(#${uid})`} stroke={C.sageB} strokeWidth="1.4" strokeLinejoin="round"/>
      {pts.map(([x,y],i)=><circle key={i} cx={x} cy={y} r={size*.022} fill={STAT_COLORS[STATS[i].k]||C.sageB}/>)}
      {showLabels && STATS.map(({s,k},i)=>{const d=r+size*.12;return <text key={i} x={cx+Math.cos(ang[i])*d} y={cy+Math.sin(ang[i])*d} textAnchor="middle" dominantBaseline="middle" fontSize={size*.065} fill={STAT_COLORS[k]||"rgba(163,192,137,0.75)"} fontFamily="Cinzel,serif" letterSpacing="0.3">{s}</text>;})}
    </svg>
  );
}

