const todayContemplation = () => {
  const d=new Date(), start=new Date(d.getFullYear(),0,0);
  const day=Math.floor((d-start)/86400000);
  return CONTEMPLATIONS[day%CONTEMPLATIONS.length];
};

/* Titles derive from level. Post-level-10 titles will become class-dependent
   once the class system is implemented. */
function levelToTitle(lvl){
  if(lvl<5)  return "Seeker";
  if(lvl<10) return "Practitioner";
  if(lvl<20) return "Anchorholder";
  if(lvl<35) return "Steward";
  if(lvl<50) return "Keeper";
  if(lvl<70) return "Elder";
  if(lvl<90) return "Sage";
  return "Masterful";
}


